import{_ as o,c as l,o as a,ag as i}from"./chunks/framework.DVUBUV_u.js";const u=JSON.parse('{"title":"Релиз 2.4.0","description":"","frontmatter":{"title":"Релиз 2.4.0"},"headers":[],"relativePath":"releases/2.4.0.md","filePath":"releases/2.4.0.md"}'),c={name:"releases/2.4.0.md"};function d(r,e,t,s,n,h){return a(),l("div",null,[...e[0]||(e[0]=[i('<hr><h2 id="_2-4-0-2026-04-19" tabindex="-1">[2.4.0] - 2026-04-19 <a class="header-anchor" href="#_2-4-0-2026-04-19" aria-label="Permalink to &quot;[2.4.0] - 2026-04-19&quot;">​</a></h2><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Таблица <code>Network</code> переведена на виртуализацию для ускорения работы и снижения фризов.</li><li>Изменено стартовое окно при открытии детализации запроса — по умолчанию теперь открывается <code>Response</code>.</li><li>При срабатывании <code>Breakpoint</code> остановленный метод автоматически открывается на вкладке <code>Request</code>.</li><li>При установке паузы, перехватчики инспектора теперь снимаются, в стандартных Devtools будет отображаться оригинальный инициатор вместо injected.ts.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li><p>Значительно ускорена работа с <code>Props</code>, что позволяет безопасно использовать автообновление данных.</p></li><li><p>В таблице <code>Props</code> колонка <code>Props</code> заменена на <code>Passed</code> и <code>Declared</code> (все колонки доступны для скрытия):</p><ul><li><code>Passed</code> — количество <code>Props</code>, полученных в текущий момент.</li><li><code>Declared</code> — количество возможных <code>Props</code>, объявленных для элемента.</li></ul></li><li><p>В блоке <code>Details Props</code> добавлен параметр <code>Size</code>.</p></li></ul><h4 id="inspect-props-inspector" tabindex="-1">Inspect (<code>Props Inspector</code>) <a class="header-anchor" href="#inspect-props-inspector" aria-label="Permalink to &quot;Inspect (`Props Inspector`)&quot;">​</a></h4><ul><li>Добавлен режим выбора элементов на странице по аналогии с <code>Chrome DevTools Elements</code>.</li><li>Позволяет выбрать элемент прямо на странице и быстро отфильтровать список <code>Props</code>.</li><li>Подсвечивает <code>Vue</code>-компоненты при наведении.</li><li>Показывает краткую информацию об элементе: <code>Name</code>, <code>Root element</code>, <code>Received Props</code>, <code>Nested components</code>.</li><li>После выбора отображает <code>Props</code> только выбранного элемента и его вложенных компонентов.</li><li>Фильтр можно быстро сбросить через бейдж <code>Filtered</code>.</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><h4 id="оконныи-режим" tabindex="-1">Оконный режим <a class="header-anchor" href="#оконныи-режим" aria-label="Permalink to &quot;Оконный режим&quot;">​</a></h4><ul><li>Добавлена поддержка оконного режима приложения с сохранением выбранного положения для обеих версий запуска.</li><li>Обновлён шеврон открытия <code>iframe</code> — добавлена иконка перетаскивания.</li><li>Добавлена возможность закрепления шеврона по любой из четырёх сторон браузера с автоматическим растягиванием окна приложения по высоте.</li></ul><h4 id="настроики-автозапуска" tabindex="-1">Настройки автозапуска <a class="header-anchor" href="#настроики-автозапуска" aria-label="Permalink to &quot;Настройки автозапуска&quot;">​</a></h4><ul><li><p>Добавлена возможность задать список сайтов для автоматического запуска приложения (<code>Whitelist</code>) и список исключений, где запуск приложения и отображение шеврона запрещены (<code>Blacklist</code>).</p></li><li><p>Добавлено <code>popup</code>-меню расширения с быстрыми действиями:</p><ul><li><code>Forced Launch</code> - Принудительный запуск приложения (игнорирует ограничения white и blacklist site, а так же внутреннее ограничение на статичные сайты);</li><li><code>Reset Settings</code> - Сброс всех настроек расширения.</li></ul></li></ul><h4 id="прочие-улучшения-интерфеиса" tabindex="-1">Прочие улучшения интерфейса <a class="header-anchor" href="#прочие-улучшения-интерфеиса" aria-label="Permalink to &quot;Прочие улучшения интерфейса&quot;">​</a></h4><ul><li>Исправлены стили <code>JSON</code> для больших объёмов данных.</li><li>Добавлена возможность точного поиска при вводе значения в кавычках: без кавычек поиск работает в режиме <code>like</code>.</li><li>Внесены мелкие визуальные правки интерфейса.</li><li>Доработана логика закрытия вкладок по клавише <code>Esc</code> в режиме <code>DevTools</code>: сначала выполняется выход из вкладок, а если закрывать больше нечего — открывается консоль <code>DevTools</code>.</li></ul><hr><h3 id="производительность" tabindex="-1">Производительность <a class="header-anchor" href="#производительность" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Изменён механизм определения <code>Props</code> и <code>Store</code> — получение данных значительно ускорено.</li><li>Увеличены лимиты на максимальное количество вычитываемых <code>Props</code>.</li><li>Проведён рефакторинг внутренней структуры проекта: удалены неиспользуемые модули, мёртвый код и дублирующая логика.</li></ul><hr><h3 id="документация" tabindex="-1">Документация <a class="header-anchor" href="#документация" aria-label="Permalink to &quot;Документация&quot;">​</a></h3><ul><li>У проекта появилась полноценная документация.</li><li>На лендинговой странице добавлен раздел <code>Documentation</code>.</li><li>В разделе <code>Options → About</code> добавлен быстрый переход к документации.</li></ul><hr><h3 id="исправления" tabindex="-1">Исправления <a class="header-anchor" href="#исправления" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Заблокирована работа стандартного ПКМ внутри контекстного меню приложения.</li><li>Доработана логика работы поиска для Devtools mode. Исправлен кейс, когда поиск мог перестать работать, добавлена логика сброса подсветки при очистке поля или закрытия функционала поиска.</li></ul>',26)])])}const P=o(c,[["render",d]]);export{u as __pageData,P as default};
